```razor
@page "/"
@attribute [Authorize]
@rendermode InteractiveServer
@using Microsoft.AspNetCore.Authorization
@using Microsoft.EntityFrameworkCore
@inject IDbContextFactory<VetClinic.Data.ApplicationDbContext> DbFactory

<PageTitle>VetClinic - Dashboard</PageTitle>

<h1>Veterinary Clinic Dashboard</h1>

<div class="row mt-4">
    <div class="col-md-3">
        <div class="card text-bg-primary mb-3">
            <div class="card-body">
                <h5 class="card-title">Patients</h5>
                <p class="card-text display-6">@petCount</p>
            </div>
        </div>
    </div>
    <div class="col-md-3">
        <div class="card text-bg-success mb-3">
            <div class="card-body">
                <h5 class="card-title">Today's Appointments</h5>
                <p class="card-text display-6">@todayAppointments</p>
            </div>
        </div>
    </div>
    <div class="col-md-3">
        <div class="card text-bg-warning mb-3">
            <div class="card-body">
                <h5 class="card-title">Pending Invoices</h5>
                <p class="card-text display-6">@pendingInvoices</p>
            </div>
        </div>
    </div>
    <div class="col-md-3">
        <div class="card text-bg-info mb-3">
            <div class="card-body">
                <h5 class="card-title">Owners</h5>
                <p class="card-text display-6">@ownerCount</p>
            </div>
        </div>
    </div>
</div>

<h3 class="mt-4">Upcoming Appointments</h3>
<table class="table table-striped">
    <thead>
        <tr><th>Time</th><th>Pet</th><th>Owner</th><th>Reason</th><th>Status</th></tr>
    </thead>
    <tbody>
        @foreach (var apt in upcomingAppointments)
        {
            <tr>
                <td>@apt.ScheduledAt.ToString("g")</td>
                <td>@apt.Pet.Name</td>
                <td>@apt.Pet.Owner.LastName</td>
                <td>@apt.Reason</td>
                <td><span class="badge bg-@GetStatusColor(apt.Status)">@apt.Status</span></td>
            </tr>
        }
    </tbody>
</table>

@code {
    private int petCount, todayAppointments, pendingInvoices, ownerCount;
    private List<VetClinic.Data.Appointment> upcomingAppointments = new();

    protected override async Task OnInitializedAsync()
    {
        using var db = await DbFactory.CreateDbContextAsync();
        petCount = await db.Pets.CountAsync();
        ownerCount = await db.Owners.CountAsync();
        todayAppointments = await db.Appointments
            .Where(a => a.ScheduledAt.Date == DateTime.Today && a.Status == VetClinic.Data.AppointmentStatus.Scheduled)
            .CountAsync();
        pendingInvoices = await db.Invoices
            .Where(i => i.Status != VetClinic.Data.InvoiceStatus.Paid)
            .CountAsync();
        upcomingAppointments = await db.Appointments
            .Include(a => a.Pet).ThenInclude(p => p.Owner)
            .Where(a => a.ScheduledAt >= DateTime.Now && a.Status == VetClinic.Data.AppointmentStatus.Scheduled)
            .OrderBy(a => a.ScheduledAt)
            .Take(10)
            .ToListAsync();
    }

    private string GetStatusColor(VetClinic.Data.AppointmentStatus status) => status switch
    {
        VetClinic.Data.AppointmentStatus.Scheduled => "primary",
        VetClinic.Data.AppointmentStatus.Completed => "success",
        VetClinic.Data.AppointmentStatus.Cancelled => "secondary",
        _ => "light"
    };
}
```

