        if (editingOwner.Id == 0) db.Owners.Add(editingOwner);
        else db.Owners.Update(editingOwner);
        await db.SaveChangesAsync();
        showOwnerForm = false;
        await LoadData();
    }

    private async Task SavePet()
    {
        editingPet.DateOfBirth = DateOnly.FromDateTime(petDob);
        using var db = await DbFactory.CreateDbContextAsync();
        if (editingPet.Id == 0) db.Pets.Add(editingPet);
        else db.Pets.Update(editingPet);
        await db.SaveChangesAsync();
        showPetForm = false;
        await LoadData();
    }

