```razor
@page "/appointments"
@attribute [Authorize]
@rendermode InteractiveServer
@using Microsoft.AspNetCore.Authorization
@using Microsoft.EntityFrameworkCore
@inject IDbContextFactory<VetClinic.Data.ApplicationDbContext> DbFactory

