            <div class="card-body">
                @foreach (var slot in availableSlots)
                {
                    <span class="badge bg-success me-1 mb-1 p-2">@slot.ToString("HH:mm")</span>
                }
                @if (!availableSlots.Any())
                {
                    <p class="text-muted">No available slots</p>
                }
            </div>
        </div>
    </div>
</div>

@code {
    private DateTime selectedDate = DateTime.Today;
    private DateTime appointmentDateTime = DateTime.Today.AddHours(9);
    private List<VetClinic.Data.Appointment> appointments = new();
    private List<VetClinic.Data.Pet> allPets = new();
    private List<DateTime> availableSlots = new();
    private VetClinic.Data.Appointment editingAppointment = new();
    private bool showForm;
    private string formError = "";

    protected override async Task OnInitializedAsync()
    {
        using var db = await DbFactory.CreateDbContextAsync();
        allPets = await db.Pets.Include(p => p.Owner).OrderBy(p => p.Name).ToListAsync();
        await LoadAppointments();
    }

    private async Task LoadAppointments()
    {
        using var db = await DbFactory.CreateDbContextAsync();
        appointments = await db.Appointments
            .Include(a => a.Pet).ThenInclude(p => p.Owner)
            .Where(a => a.ScheduledAt.Date == selectedDate.Date)
            .OrderBy(a => a.ScheduledAt)
            .ToListAsync();
        CalculateAvailableSlots();
    }

    private void CalculateAvailableSlots()
    {
        availableSlots.Clear();
        var start = selectedDate.Date.AddHours(8);
        var end = selectedDate.Date.AddHours(18);
        var scheduled = appointments
            .Where(a => a.Status == VetClinic.Data.AppointmentStatus.Scheduled)
            .ToList();

        for (var time = start; time < end; time = time.AddMinutes(30))
        {
            var slotEnd = time.AddMinutes(30);
            bool conflict = scheduled.Any(a =>
                a.ScheduledAt < slotEnd && a.ScheduledAt.AddMinutes(a.DurationMinutes) > time);
            if (!conflict) availableSlots.Add(time);
        }
    }

    private void ShowNewAppointment()
    {
        editingAppointment = new VetClinic.Data.Appointment { DurationMinutes = 30 };
        appointmentDateTime = selectedDate.Date.AddHours(9);
        formError = "";
        showForm = true;
    }

    private async Task SaveAppointment()
    {
        editingAppointment.ScheduledAt = appointmentDateTime;
        // Check for conflicts
        using var db = await DbFactory.CreateDbContextAsync();
        var conflict = await db.Appointments
            .Where(a => a.Id != editingAppointment.Id && a.Status == VetClinic.Data.AppointmentStatus.Scheduled)
            .Where(a => a.ScheduledAt < editingAppointment.ScheduledAt.AddMinutes(editingAppointment.DurationMinutes)
                && a.ScheduledAt.AddMinutes(a.DurationMinutes) > editingAppointment.ScheduledAt)
            .AnyAsync();

        if (conflict)
        {
            formError = "Time slot conflicts with an existing appointment.";
            return;
        }

        if (editingAppointment.Id == 0)
            db.Appointments.Add(editingAppointment);
        else
            db.Appointments.Update(editingAppointment);

        await db.SaveChangesAsync();
        showForm = false;
        selectedDate = editingAppointment.ScheduledAt.Date;
        await LoadAppointments();
    }

    private void Reschedule(VetClinic.Data.Appointment apt)
    {
        editingAppointment = new VetClinic.Data.Appointment
        {
            Id = apt.Id, PetId = apt.PetId, Reason = apt.Reason,
            DurationMinutes = apt.DurationMinutes, Notes = apt.Notes,
            Status = apt.Status
        };
        appointmentDateTime = apt.ScheduledAt;
        formError = "";
        showForm = true;
    }

    private async Task Cancel(VetClinic.Data.Appointment apt)
    {
        using var db = await DbFactory.CreateDbContextAsync();
        var entity = await db.Appointments.FindAsync(apt.Id);
        if (entity != null)
        {
            entity.Status = VetClinic.Data.AppointmentStatus.Cancelled;
            await db.SaveChangesAsync();
        }
        await LoadAppointments();
    }

    private async Task Complete(VetClinic.Data.Appointment apt)
    {
        using var db = await DbFactory.CreateDbContextAsync();
        var entity = await db.Appointments.FindAsync(apt.Id);
        if (entity != null)
        {
            entity.Status = VetClinic.Data.AppointmentStatus.Completed;
            await db.SaveChangesAsync();
        }
        await LoadAppointments();
    }

    private string GetColor(VetClinic.Data.AppointmentStatus s) => s switch
    {
        VetClinic.Data.AppointmentStatus.Scheduled => "primary",
        VetClinic.Data.AppointmentStatus.Completed => "success",
        VetClinic.Data.AppointmentStatus.Cancelled => "secondary",
        _ => "light"
    };
}
