            <button class="btn btn-secondary mt-2" @onclick="() => showForm = false">Cancel</button>
        </div>
    </div>
}

<h4>Schedule for @selectedDate.ToString("D")</h4>
<div class="row">
    <div class="col-md-8">
        <table class="table table-bordered">
            <thead><tr><th>Time</th><th>Pet</th><th>Owner</th><th>Reason</th><th>Duration</th><th>Status</th><th>Actions</th></tr></thead>
            <tbody>
                @foreach (var apt in appointments)
                {
                    <tr class="@(apt.Status == VetClinic.Data.AppointmentStatus.Cancelled ? "table-secondary" : "")">
