@page "/patients"
@attribute [Authorize]
@rendermode InteractiveServer
@using Microsoft.AspNetCore.Authorization
@using Microsoft.EntityFrameworkCore
@inject IDbContextFactory<VetClinic.Data.ApplicationDbContext> DbFactory

<PageTitle>Patients</PageTitle>

<h1>Patient Records</h1>

<div class="row mb-3">
    <div class="col">
        <input class="form-control" placeholder="Search by pet name or owner..." @bind="searchTerm" @bind:event="oninput" @bind:after="Search" />
    </div>
    <div class="col-auto">
        <button class="btn btn-primary" @onclick="ShowAddOwner">+ New Owner</button>
        <button class="btn btn-success ms-2" @onclick="ShowAddPet">+ New Pet</button>
    </div>
</div>

@if (showOwnerForm)
{
    <div class="card mb-3">
        <div class="card-body">
            <h5>@(editingOwner.Id == 0 ? "New Owner" : "Edit Owner")</h5>
            <div class="row g-2">
                <div class="col-md-3"><input class="form-control" placeholder="First Name" @bind="editingOwner.FirstName" /></div>
                <div class="col-md-3"><input class="form-control" placeholder="Last Name" @bind="editingOwner.LastName" /></div>
                <div class="col-md-3"><input class="form-control" placeholder="Phone" @bind="editingOwner.Phone" /></div>
                <div class="col-md-3"><input class="form-control" placeholder="Email" @bind="editingOwner.Email" /></div>
            </div>
            <button class="btn btn-primary mt-2" @onclick="SaveOwner">Save</button>
            <button class="btn btn-secondary mt-2" @onclick="() => showOwnerForm = false">Cancel</button>
        </div>
    </div>
}

@if (showPetForm)
{
    <div class="card mb-3">
        <div class="card-body">
            <h5>@(editingPet.Id == 0 ? "Register New Pet" : "Edit Pet")</h5>
            <div class="row g-2">
                <div class="col-md-2"><input class="form-control" placeholder="Name" @bind="editingPet.Name" /></div>
                <div class="col-md-2"><input class="form-control" placeholder="Species" @bind="editingPet.Species" /></div>
                <div class="col-md-2"><input class="form-control" placeholder="Breed" @bind="editingPet.Breed" /></div>
                <div class="col-md-2"><input type="date" class="form-control" @bind="petDob" /></div>
                <div class="col-md-2"><input type="number" step="0.1" class="form-control" placeholder="Weight (kg)" @bind="editingPet.Weight" /></div>
                <div class="col-md-2">
                    <select class="form-select" @bind="editingPet.OwnerId">
                        <option value="0">Select Owner</option>
                        @foreach (var o in owners)
                        {
                            <option value="@o.Id">@o.LastName, @o.FirstName</option>
                        }
                    </select>
                </div>
            </div>
            <button class="btn btn-success mt-2" @onclick="SavePet">Save</button>
            <button class="btn btn-secondary mt-2" @onclick="() => showPetForm = false">Cancel</button>
        </div>
    </div>
}

<table class="table table-hover">
    <thead>
        <tr><th>Name</th><th>Species</th><th>Breed</th><th>Age</th><th>Weight</th><th>Owner</th><th>Actions</th></tr>
    </thead>
    <tbody>
        @foreach (var pet in pets)
        {
            <tr>
                <td>@pet.Name</td>
                <td>@pet.Species</td>
                <td>@pet.Breed</td>
                <td>@GetAge(pet.DateOfBirth)</td>
                <td>@pet.Weight kg</td>
                <td>@pet.Owner.FirstName @pet.Owner.LastName</td>
                <td>
                    <button class="btn btn-sm btn-outline-primary" @onclick="() => EditPet(pet)">Edit</button>
                    <button class="btn btn-sm btn-outline-info" @onclick="() => ViewHistory(pet)">History</button>
                </td>
            </tr>
        }
    </tbody>
</table>

@if (showHistory && selectedPet != null)
{
    <div class="card mt-3">
        <div class="card-header d-flex justify-content-between">
            <span>Medical History - @selectedPet.Name</span>
            <button class="btn btn-sm btn-outline-success" @onclick="ShowAddTreatment">+ Add Treatment</button>
        </div>
        <div class="card-body">
            @if (showTreatmentForm)
            {
                <div class="border p-3 mb-3">
                    <div class="row g-2">
                        <div class="col-md-3"><input class="form-control" placeholder="Diagnosis" @bind="editingTreatment.Diagnosis" /></div>
                        <div class="col-md-3"><input class="form-control" placeholder="Description" @bind="editingTreatment.Description" /></div>
                        <div class="col-md-3"><input class="form-control" placeholder="Medication" @bind="editingTreatment.Medication" /></div>
                        <div class="col-md-3"><input class="form-control" placeholder="Performed By" @bind="editingTreatment.PerformedBy" /></div>
                    </div>
                    <div class="mt-2">
                        <textarea class="form-control" placeholder="Notes" @bind="editingTreatment.Notes"></textarea>
                    </div>
                    <button class="btn btn-success mt-2" @onclick="SaveTreatment">Save Treatment</button>
                    <button class="btn btn-secondary mt-2" @onclick="() => showTreatmentForm = false">Cancel</button>
                </div>
            }
            <table class="table table-sm">
                <thead><tr><th>Date</th><th>Diagnosis</th><th>Description</th><th>Medication</th><th>By</th><th>Notes</th></tr></thead>
                <tbody>
                    @foreach (var t in treatments)
                    {
                        <tr>
                            <td>@t.Date.ToString("d")</td>
                            <td>@t.Diagnosis</td>
                            <td>@t.Description</td>
                            <td>@t.Medication</td>
                            <td>@t.PerformedBy</td>
                            <td>@t.Notes</td>
                        </tr>
                    }
                </tbody>
            </table>
        </div>
    </div>
}

@code {
    private List<VetClinic.Data.Pet> pets = new();
    private List<VetClinic.Data.Owner> owners = new();
    private List<VetClinic.Data.Treatment> treatments = new();
    private string searchTerm = "";
    private bool showOwnerForm, showPetForm, showHistory, showTreatmentForm;
    private VetClinic.Data.Owner editingOwner = new();
    private VetClinic.Data.Pet editingPet = new();
    private VetClinic.Data.Pet? selectedPet;
    private VetClinic.Data.Treatment editingTreatment = new();
    private DateTime petDob = DateTime.Today;

    protected override async Task OnInitializedAsync() => await LoadData();

    private async Task LoadData()
    {
        using var db = await DbFactory.CreateDbContextAsync();
        pets = await db.Pets.Include(p => p.Owner).OrderBy(p => p.Name).ToListAsync();
        owners = await db.Owners.OrderBy(o => o.LastName).ToListAsync();
    }

    private async Task Search()
    {
        using var db = await DbFactory.CreateDbContextAsync();
        var q = db.Pets.Include(p => p.Owner).AsQueryable();
        if (!string.IsNullOrWhiteSpace(searchTerm))
            q = q.Where(p => p.Name.Contains(searchTerm) || p.Owner.LastName.Contains(searchTerm));
        pets = await q.OrderBy(p => p.Name).ToListAsync();
    }

    private void ShowAddOwner() { editingOwner = new(); showOwnerForm = true; }
    private void ShowAddPet() { editingPet = new(); showPetForm = true; }

    private async Task SaveOwner()
    {
        using var db = await DbFactory.CreateDbContextAsync();
        if (editingOwner.Id == 0) db.Owners.Add(editingOwner);
        else db.Owners.Update(editingOwner);
        await db.SaveChangesAsync();
        showOwnerForm = false;
        await LoadData();
    }

    private async Task SavePet()
    {
        editingPet.DateOfBirth = DateOnly.FromDateTime(petDob);
        using var db = await DbFactory.CreateDbContextAsync();
        if (editingPet.Id == 0) db.Pets.Add(editingPet);
        else db.Pets.Update(editingPet);
        await db.SaveChangesAsync();
        showPetForm = false;
        await LoadData();
    }

    private void EditPet(VetClinic.Data.Pet pet)
    {
        editingPet = new VetClinic.Data.Pet
        {
            Id = pet.Id, Name = pet.Name, Species = pet.Species, Breed = pet.Breed,
            DateOfBirth = pet.DateOfBirth, Weight = pet.Weight, OwnerId = pet.OwnerId
        };
        petDob = pet.DateOfBirth.ToDateTime(TimeOnly.MinValue);
        showPetForm = true;
    }

    private async Task ViewHistory(VetClinic.Data.Pet pet)
    {
        selectedPet = pet;
        showHistory = true;
        using var db = await DbFactory.CreateDbContextAsync();
        treatments = await db.Treatments.Where(t => t.PetId == pet.Id).OrderByDescending(t => t.Date).ToListAsync();
    }

    private void ShowAddTreatment()
    {
        editingTreatment = new VetClinic.Data.Treatment { PetId = selectedPet!.Id, Date = DateTime.Now };
        showTreatmentForm = true;
    }

    private async Task SaveTreatment()
    {
        using var db = await DbFactory.CreateDbContextAsync();
        db.Treatments.Add(editingTreatment);
        await db.SaveChangesAsync();
        showTreatmentForm = false;
        await ViewHistory(selectedPet!);
    }

    private string GetAge(DateOnly dob)
    {
        var today = DateOnly.FromDateTime(DateTime.Today);
        int years = today.Year - dob.Year;
        if (dob.AddYears(years) > today) years--;
        return years > 0 ? $"{years}y" : $"{today.DayNumber - dob.DayNumber / 30}m";
    }
}

@page "/appointments"
@attribute [Authorize]
@rendermode InteractiveServer
@using Microsoft.AspNetCore.Authorization
@using Microsoft.EntityFrameworkCore
@inject IDbContextFactory<VetClinic.Data.ApplicationDbContext> DbFactory

<PageTitle>Appointments</PageTitle>

<h1>Appointment Scheduling</h1>

<div class="row mb-3">
    <div class="col-md-3">
        <label class="form-label">View Date</label>
        <input type="date" class="form-control" @bind="selectedDate" @bind:after="LoadAppointments" />
    </div>
    <div class="col-md-3 d-flex align-items-end">
        <button class="btn btn-primary" @onclick="ShowNewAppointment">+ New Appointment</button>
    </div>
</div>

@if (showForm)
{
    <div class="card mb-3">
        <div class="card-body">
            <h5>@(editingAppointment.Id == 0 ? "Schedule Appointment" : "Edit Appointment")</h5>
            <div class="row g-2">
                <div class="col-md-3">
                    <label class="form-label">Pet</label>
                    <select class="form-select" @bind="editingAppointment.PetId">
                        <option value="0">Select Pet</option>
                        @foreach (var p in allPets)
                        {
                            <option value="@p.Id">@p.Name (@p.Owner.LastName)</option>
                        }
                    </select>
                </div>
                <div class="col-md-3">
                    <label class="form-label">Date &amp; Time</label>
                    <input type="datetime-local" class="form-control" @bind="appointmentDateTime" />
                </div>
                <div class="col-md-2">
                    <label class="form-label">Duration (min)</label>
                    <input type="number" class="form-control" @bind="editingAppointment.DurationMinutes" />
                </div>
                <div class="col-md-4">
                    <label class="form-label">Reason</label>
                    <input class="form-control" @bind="editingAppointment.Reason" />
                </div>
            </div>
            <div class="mt-2">
                <textarea class="form-control" placeholder="Notes" @bind="editingAppointment.Notes"></textarea>
            </div>
            @if (!string.IsNullOrEmpty(formError))
            {
                <div class="alert alert-danger mt-2">@formError</div>
            }
            <button class="btn btn-primary mt-2" @onclick="SaveAppointment">Save</button>
            <button class="btn btn-secondary mt-2" @onclick="() => showForm = false">Cancel</button>
        </div>
    </div>
}

<h4>Schedule for @selectedDate.ToString("D")</h4>
<div class="row">
    <div class="col-md-8">
        <table class="table table-bordered">
            <thead><tr><th>Time</th><th>Pet</th><th>Owner</th><th>Reason</th><th>Duration</th><th>Status</th><th>Actions</th></tr></thead>
            <tbody>
                @foreach (var apt in appointments)
                {
                    <tr class="@(apt.Status == VetClinic.Data.AppointmentStatus.Cancelled ? "table-secondary" : "")">
                        <td>@apt.ScheduledAt.ToString("HH:mm")</td>
                        <td>@apt.Pet.Name</td>
                        <td>@apt.Pet.Owner.LastName</td>
                        <td>@apt.Reason</td>
                        <td>@apt.DurationMinutes min</td>
                        <td><span class="badge bg-@GetColor(apt.Status)">@apt.Status</span></td>
                        <td>
                            @if (apt.Status == VetClinic.Data.AppointmentStatus.Scheduled)
                            {
                                <button class="btn btn-sm btn-outline-warning" @onclick="() => Reschedule(apt)">Reschedule</button>
                                <button class="btn btn-sm btn-outline-danger" @onclick="() => Cancel(apt)">Cancel</button>
                                <button class="btn btn-sm btn-outline-success" @onclick="() => Complete(apt)">Complete</button>
                            }
                        </td>
                    </tr>
                }
                @if (!appointments.Any())
                {
                    <tr><td colspan="7" class="text-center text-muted">No appointments for this date</td></tr>
                }
            </tbody>
        </table>
    </div>
    <div class="col-md-4">
        <div class="card">
            <div class="card-header">Available Slots</div>
            <div class="card-body">
                @foreach (var slot in availableSlots)
                {
                    <span class="badge bg-success me-1 mb-1 p-2">@slot.ToString("HH:mm")</span>
                }
                @if (!availableSlots.Any())
                {
                    <p class="text-muted">No available slots</p>
                }
            </div>
        </div>
    </div>
</div>

@code {
    private DateTime selectedDate = DateTime.Today;
    private DateTime appointmentDateTime = DateTime.Today.AddHours(9);
    private List<VetClinic.Data.Appointment> appointments = new();
    private List<VetClinic.Data.Pet> allPets = new();
    private List<DateTime> availableSlots = new();
    private VetClinic.Data.Appointment editingAppointment = new();
    private bool showForm;
    private string formError = "";

    protected override async Task OnInitializedAsync()
    {
        using var db = await DbFactory.CreateDbContextAsync();
        allPets = await db.Pets.Include(p => p.Owner).OrderBy(p => p.Name).ToListAsync();
        await LoadAppointments();
    }

    private async Task LoadAppointments()
    {
        using var db = await DbFactory.CreateDbContextAsync();
        appointments = await db.Appointments
            .Include(a => a.Pet).ThenInclude(p => p.Owner)
            .Where(a => a.ScheduledAt.Date == selectedDate.Date)
            .OrderBy(a => a.ScheduledAt)
            .ToListAsync();
        CalculateAvailableSlots();
    }

    private void CalculateAvailableSlots()
    {
        availableSlots.Clear();
        var start = selectedDate.Date.AddHours(8);
        var end = selectedDate.Date.AddHours(18);
        var scheduled = appointments
            .Where(a => a.Status == VetClinic.Data.AppointmentStatus.Scheduled)
            .ToList();

        for (var time = start; time < end; time = time.AddMinutes(30))
        {
            var slotEnd = time.AddMinutes(30);
            bool conflict = scheduled.Any(a =>
                a.ScheduledAt < slotEnd && a.ScheduledAt.AddMinutes(a.DurationMinutes) > time);
            if (!conflict) availableSlots.Add(time);
        }
    }

    private void ShowNewAppointment()
    {
        editingAppointment = new VetClinic.Data.Appointment { DurationMinutes = 30 };
        appointmentDateTime = selectedDate.Date.AddHours(9);
        formError = "";
        showForm = true;
    }

    private async Task SaveAppointment()
    {
        editingAppointment.ScheduledAt = appointmentDateTime;
        // Check for conflicts
        using var db = await DbFactory.CreateDbContextAsync();
        var conflict = await db.Appointments
            .Where(a => a.Id != editingAppointment.Id && a.Status == VetClinic.Data.AppointmentStatus.Scheduled)
            .Where(a => a.ScheduledAt < editingAppointment.ScheduledAt.AddMinutes(editingAppointment.DurationMinutes)
                && a.ScheduledAt.AddMinutes(a.DurationMinutes) > editingAppointment.ScheduledAt)
            .AnyAsync();

        if (conflict)
        {
            formError = "Time slot conflicts with an existing appointment.";
            return;
        }

        if (editingAppointment.Id == 0)
            db.Appointments.Add(editingAppointment);
        else
            db.Appointments.Update(editingAppointment);

        await db.SaveChangesAsync();
        showForm = false;
        selectedDate = editingAppointment.ScheduledAt.Date;
        await LoadAppointments();
    }

    private void Reschedule(VetClinic.Data.Appointment apt)
    {
        editingAppointment = new VetClinic.Data.Appointment
        {
            Id = apt.Id, PetId = apt.PetId, Reason = apt.Reason,
            DurationMinutes = apt.DurationMinutes, Notes = apt.Notes,
            Status = apt.Status
        };
        appointmentDateTime = apt.ScheduledAt;
        formError = "";
        showForm = true;
    }

    private async Task Cancel(VetClinic.Data.Appointment apt)
    {
        using var db = await DbFactory.CreateDbContextAsync();
        var entity = await db.Appointments.FindAsync(apt.Id);
        if (entity != null)
        {
            entity.Status = VetClinic.Data.AppointmentStatus.Cancelled;
            await db.SaveChangesAsync();
        }
        await LoadAppointments();
    }

    private async Task Complete(VetClinic.Data.Appointment apt)
    {
        using var db = await DbFactory.CreateDbContextAsync();
        var entity = await db.Appointments.FindAsync(apt.Id);
        if (entity != null)
        {
            entity.Status = VetClinic.Data.AppointmentStatus.Completed;
            await db.SaveChangesAsync();
        }
        await LoadAppointments();
    }

    private string GetColor(VetClinic.Data.AppointmentStatus s) => s switch
    {
        VetClinic.Data.AppointmentStatus.Scheduled => "primary",
        VetClinic.Data.AppointmentStatus.Completed => "success",
        VetClinic.Data.AppointmentStatus.Cancelled => "secondary",
        _ => "light"
    };
}

