@code {
    private List<VetClinic.Data.Invoice> invoices = new();
    private List<VetClinic.Data.Pet> allPets = new();
    private VetClinic.Data.Invoice newInvoice = new();
    private VetClinic.Data.Invoice? selectedInvoice;
    private bool showInvoiceForm, showPaymentForm, showPayments;
    private string statusFilter = "";
    private decimal paymentAmount;
    private string paymentMethod = "Cash";

    protected override async Task OnInitializedAsync()
    {
        using var db = await DbFactory.CreateDbContextAsync();
        allPets = await db.Pets.Include(p => p.Owner).OrderBy(p => p.Name).ToListAsync();
        await LoadInvoices();
    }

    private async Task LoadInvoices()
    {
        using var db = await DbFactory.CreateDbContextAsync();
        var q = db.Invoices.Include(i => i.Pet).ThenInclude(p => p.Owner).Include(i => i.Payments).AsQueryable();
        if (!string.IsNullOrEmpty(statusFilter) && Enum.TryParse<VetClinic.Data.InvoiceStatus>(statusFilter, out var s))
            q = q.Where(i => i.Status == s);
        invoices = await q.OrderByDescending(i => i.IssuedAt).ToListAsync();
    }

    private void ShowNewInvoice()
    {
        newInvoice = new VetClinic.Data.Invoice { IssuedAt = DateTime.Now };
        showInvoiceForm = true;
    }

    private async Task SaveInvoice()
    {
        using var db = await DbFactory.CreateDbContextAsync();
        db.Invoices.Add(newInvoice);
        await db.SaveChangesAsync();
        showInvoiceForm = false;
        await LoadInvoices();
    }

    private void ShowPayment(VetClinic.Data.Invoice inv)
    {
        selectedInvoice = inv;
        paymentAmount = inv.Amount - inv.Payments.Sum(p => p.Amount);
        paymentMethod = "Cash";
        showPaymentForm = true;
        showPayments = false;
    }

    private void ShowPaymentHistory(VetClinic.Data.Invoice inv)
    {
        selectedInvoice = inv;
        showPayments = true;
        showPaymentForm = false;
    }

    private async Task ProcessPayment()
    {
        if (selectedInvoice == null) return;
        using var db = await DbFactory.CreateDbContextAsync();
        var payment = new VetClinic.Data.Payment
        {
            InvoiceId = selectedInvoice.Id,
            Amount = paymentAmount,
            Method = paymentMethod,
            PaidAt = DateTime.Now
        };
        db.Payments.Add(payment);

        var invoice = await db.Invoices.Include(i => i.Payments).FirstAsync(i => i.Id == selectedInvoice.Id);
        var totalPaid = invoice.Payments.Sum(p => p.Amount) + paymentAmount;
        invoice.Status = totalPaid >= invoice.Amount ? VetClinic.Data.InvoiceStatus.Paid : VetClinic.Data.InvoiceStatus.PartiallyPaid;

        await db.SaveChangesAsync();
        showPaymentForm = false;
        await LoadInvoices();
    }

    private string GetInvoiceColor(VetClinic.Data.InvoiceStatus s) => s switch
    {
        VetClinic.Data.InvoiceStatus.Pending => "warning",
        VetClinic.Data.InvoiceStatus.PartiallyPaid => "info",
        VetClinic.Data.InvoiceStatus.Paid => "success",
        _ => "light"
    };
}

