@@ -1,0 +1,222 @@
+@page "/billing"
+@attribute [Authorize]
+@rendermode InteractiveServer
+@using Microsoft.AspNetCore.Authorization
+@using Microsoft.EntityFrameworkCore
+@inject IDbContextFactory<VetClinic.Data.ApplicationDbContext> DbFactory
+
+<PageTitle>Billing</PageTitle>
+
+<h1>Billing &amp; Payments</h1>
+
+<div class="row mb-3">
+    <div class="col-auto">
+        <button class="btn btn-primary" @onclick="ShowNewInvoice">+ New Invoice</button>
+    </div>
+    <div class="col">
+        <select class="form-select" @bind="statusFilter" @bind:after="LoadInvoices">
+            <option value="">All Invoices</option>
+            <option value="Pending">Pending</option>
+            <option value="PartiallyPaid">Partially Paid</option>
+            <option value="Paid">Paid</option>
+        </select>
+    </div>
+</div>
+
+@if (showInvoiceForm)
+{
+    <div class="card mb-3">
+        <div class="card-body">
+            <h5>Generate Invoice</h5>
+            <div class="row g-2">
+                <div class="col-md-4">
+                    <label class="form-label">Pet</label>
+                    <select class="form-select" @bind="newInvoice.PetId">
+                        <option value="0">Select Pet</option>
+                        @foreach (var p in allPets)
+                        {
+                            <option value="@p.Id">@p.Name (@p.Owner.LastName)</option>
+                        }
+                    </select>
+                </div>
+                <div class="col-md-3">
+                    <label class="form-label">Amount</label>
+                    <input type="number" step="0.01" class="form-control" @bind="newInvoice.Amount" />
+                </div>
+                <div class="col-md-5">
+                    <label class="form-label">Description</label>
+                    <input class="form-control" @bind="newInvoice.Description" />
+                </div>
+            </div>
+            <button class="btn btn-primary mt-2" @onclick="SaveInvoice">Generate</button>
+            <button class="btn btn-secondary mt-2" @onclick="() => showInvoiceForm = false">Cancel</button>
+        </div>
+    </div>
+}
+
+<table class="table table-striped">
+    <thead><tr><th>Invoice #</th><th>Date</th><th>Pet</th><th>Owner</th><th>Description</th><th>Amount</th><th>Paid</th><th>Status</th><th>Actions</th></tr></thead>
+    <tbody>
+        @foreach (var inv in invoices)
+        {
+            <tr>
+                <td>INV-@inv.Id.ToString("D5")</td>
+                <td>@inv.IssuedAt.ToString("d")</td>
+                <td>@inv.Pet.Name</td>
+                <td>@inv.Pet.Owner.LastName</td>
+                <td>@inv.Description</td>
+                <td>$@inv.Amount.ToString("F2")</td>
+                <td>$@inv.Payments.Sum(p => p.Amount).ToString("F2")</td>
+                <td><span class="badge bg-@GetInvoiceColor(inv.Status)">@inv.Status</span></td>
+                <td>
+                    @if (inv.Status != VetClinic.Data.InvoiceStatus.Paid)
+                    {
+                        <button class="btn btn-sm btn-outline-success" @onclick="() => ShowPayment(inv)">Pay</button>
+                    }
+                    <button class="btn btn-sm btn-outline-info" @onclick="() => ShowPaymentHistory(inv)">History</button>
+                </td>
+            </tr>
+        }
+    </tbody>
+</table>
+
+@if (showPaymentForm && selectedInvoice != null)
+{
+    <div class="card mb-3">
+        <div class="card-body">
+            <h5>Process Payment for INV-@selectedInvoice.Id.ToString("D5")</h5>
+            <p>Outstanding: $@((selectedInvoice.Amount - selectedInvoice.Payments.Sum(p => p.Amount)).ToString("F2"))</p>
+            <div class="row g-2">
+                <div class="col-md-3">
+                    <input type="number" step="0.01" class="form-control" placeholder="Amount" @bind="paymentAmount" />
+                </div>
+                <div class="col-md-3">
+                    <select class="form-select" @bind="paymentMethod">
+                        <option value="Cash">Cash</option>
+                        <option value="Card">Card</option>
+                        <option value="Transfer">Transfer</option>
+                    </select>
+                </div>
+                <div class="col-md-3">
+                    <button class="btn btn-success" @onclick="ProcessPayment">Process</button>
+                    <button class="btn btn-secondary" @onclick="() => showPaymentForm = false">Cancel</button>
+                </div>
+            </div>
+        </div>
+    </div>
+}
+
+@if (showPayments && selectedInvoice != null)
+{
+    <div class="card">
+        <div class="card-header">Payment History - INV-@selectedInvoice.Id.ToString("D5")</div>
+        <div class="card-body">
+            <table class="table table-sm">
+                <thead><tr><th>Date</th><th>Amount</th><th>Method</th></tr></thead>
+                <tbody>
+                    @foreach (var pay in selectedInvoice.Payments)
+                    {
+                        <tr>
+                            <td>@pay.PaidAt.ToString("g")</td>
+                            <td>$@pay.Amount.ToString("F2")</td>
+                            <td>@pay.Method</td>
+                        </tr>
+                    }
+                    @if (!selectedInvoice.Payments.Any())
+                    {
+                        <tr><td colspan="3" class="text-muted">No payments recorded</td></tr>
+                    }
+                </tbody>
+            </table>
+        </div>
+    </div>
+}
+
+@code {
+    private List<VetClinic.Data.Invoice> invoices = new();
+    private List<VetClinic.Data.Pet> allPets = new();
+    private VetClinic.Data.Invoice newInvoice = new();
+    private VetClinic.Data.Invoice? selectedInvoice;
+    private bool showInvoiceForm, showPaymentForm, showPayments;
+    private string statusFilter = "";
+    private decimal paymentAmount;
+    private string paymentMethod = "Cash";
+
+    protected override async Task OnInitializedAsync()
+    {
+        using var db = await DbFactory.CreateDbContextAsync();
+        allPets = await db.Pets.Include(p => p.Owner).OrderBy(p => p.Name).ToListAsync();
+        await LoadInvoices();
+    }
+
+    private async Task LoadInvoices()
+    {
+        using var db = await DbFactory.CreateDbContextAsync();
+        var q = db.Invoices.Include(i => i.Pet).ThenInclude(p => p.Owner).Include(i => i.Payments).AsQueryable();
+        if (!string.IsNullOrEmpty(statusFilter) && Enum.TryParse<VetClinic.Data.InvoiceStatus>(statusFilter, out var s))
+            q = q.Where(i => i.Status == s);
+        invoices = await q.OrderByDescending(i => i.IssuedAt).ToListAsync();
+    }
+
+    private void ShowNewInvoice()
+    {
+        newInvoice = new VetClinic.Data.Invoice { IssuedAt = DateTime.Now };
+        showInvoiceForm = true;
+    }
+
+    private async Task SaveInvoice()
+    {
+        using var db = await DbFactory.CreateDbContextAsync();
+        db.Invoices.Add(newInvoice);
+        await db.SaveChangesAsync();
+        showInvoiceForm = false;
+        await LoadInvoices();
+    }
+
+    private void ShowPayment(VetClinic.Data.Invoice inv)
+    {
+        selectedInvoice = inv;
+        paymentAmount = inv.Amount - inv.Payments.Sum(p => p.Amount);
+        paymentMethod = "Cash";
+        showPaymentForm = true;
+        showPayments = false;
+    }
+
+    private void ShowPaymentHistory(VetClinic.Data.Invoice inv)
+    {
+        selectedInvoice = inv;
+        showPayments = true;
+        showPaymentForm = false;
+    }
+
+    private async Task ProcessPayment()
+    {
+        if (selectedInvoice == null) return;
+        using var db = await DbFactory.CreateDbContextAsync();
+        var payment = new VetClinic.Data.Payment
+        {
+            InvoiceId = selectedInvoice.Id,
+            Amount = paymentAmount,
+            Method = paymentMethod,
+            PaidAt = DateTime.Now
+        };
+        db.Payments.Add(payment);
+
+        var invoice = await db.Invoices.Include(i => i.Payments).FirstAsync(i => i.Id == selectedInvoice.Id);
+        var totalPaid = invoice.Payments.Sum(p => p.Amount) + paymentAmount;
+        invoice.Status = totalPaid >= invoice.Amount ? VetClinic.Data.InvoiceStatus.Paid : VetClinic.Data.InvoiceStatus.PartiallyPaid;
+
+        await db.SaveChangesAsync();
+        showPaymentForm = false;
+        await LoadInvoices();
+    }
+
+    private string GetInvoiceColor(VetClinic.Data.InvoiceStatus s) => s switch
+    {
+        VetClinic.Data.InvoiceStatus.Pending => "warning",
+        VetClinic.Data.InvoiceStatus.PartiallyPaid => "info",
+        VetClinic.Data.InvoiceStatus.Paid => "success",
+        _ => "light"
+    };
+}
+

